245→// BuildSyntheticWebSearchToolCallText renders a Claude Code-compatible textual
246→// <tool_call> marker for Codex built-in web search events. Native Claude Code
247→// providers in this project already surface built-in web_search calls via text
248→// blocks, so we mirror that shape on the GPT-in-Claude compatibility path.
249→func BuildSyntheticWebSearchToolCallText(action gjson.Result) string {
250→	if !action.Exists() {
251→		return ""
252→	}
253→
254→	prefix := "Searching the web.\n\n"
255→	args := map[string]any{}
256→	switch strings.ToLower(strings.TrimSpace(action.Get("type").String())) {
257→	case "search":
258→		query := strings.TrimSpace(action.Get("query").String())
259→		if query != "" {
260→			prefix = "Searched: " + query + "\n\n"
261→			args["query"] = query
262→		}
263→		if queries := action.Get("queries"); queries.Exists() && queries.IsArray() {
264→			values := make([]string, 0, len(queries.Array()))
265→			for _, queryItem := range queries.Array() {
266→				queryText := strings.TrimSpace(queryItem.String())
267→				if queryText != "" {
268→					values = append(values, queryText)
269→				}
270→			}
271→			if len(values) > 0 {
272→				args["queries"] = values
273→			}
274→		}
275→	case "open_page":
276→		url := strings.TrimSpace(action.Get("url").String())
277→		if url != "" {
278→			args["url"] = url
279→		}
280→	default:
281→		if raw := strings.TrimSpace(action.Raw); raw != "" {
282→			args["action"] = json.RawMessage(raw)
283→		}
284→	}
285→
286→	if len(args) == 0 {
287→		return ""
288→	}
289→
290→	payload := map[string]any{
291→		"name":      "web_search",
292→		"arguments": args,
293→	}
294→	body, err := json.Marshal(payload)
295→	if err != nil {
296→		return ""
297→	}
298→	return prefix + "<tool_call>\n" + string(body) + "\n</tool_call>"
299→}
300→
301→// InferBuiltinWebSearchQuery extracts a likely built-in web search query from the
302→// latest Claude user message. This is only used on the Claude -> GPT compatibility
303→// path to surface an early synthetic tool call before Codex emits the final
304→// web_search_call action payload.
305→func InferBuiltinWebSearchQuery(rawJSON []byte) string {
306→	if !HasBuiltinWebSearch(rawJSON) {
307→		return ""
308→	}
309→
310→	if text := extractLatestUserText(rawJSON); text != "" {
311→		if query := normalizeLikelyWebSearchQuery(text); query != "" {
312→			return query
313→		}
314→	}
315→
316→	return ""
317→}
