319→func extractLatestUserText(rawJSON []byte) string {
320→	messages := gjson.GetBytes(rawJSON, "messages")
321→	if !messages.IsArray() {
322→		return ""
323→	}
324→
325→	for i := len(messages.Array()) - 1; i >= 0; i-- {
326→		message := messages.Array()[i]
327→		if !strings.EqualFold(strings.TrimSpace(message.Get("role").String()), "user") {
328→			continue
329→		}
330→
331→		content := message.Get("content")
332→		if content.Type == gjson.String {
333→			return content.String()
334→		}
335→		if content.IsArray() {
336→			parts := content.Array()
337→			for j := len(parts) - 1; j >= 0; j-- {
338→				part := parts[j]
339→				if strings.EqualFold(strings.TrimSpace(part.Get("type").String()), "text") {
340→					return part.Get("text").String()
341→				}
342→			}
343→		}
344→	}
345→
346→	return ""
347→}
348→
349→func hasExplicitBuiltinWebSearchIntent(text string) bool {
350→	text = strings.TrimSpace(text)
351→	if text == "" {
352→		return false
353→	}
354→
355→	if extractExplicitSearchQuery(text) != "" {
356→		return true
357→	}
358→
359→	lower := strings.ToLower(text)
360→	intentFragments := []string{
361→		"perform a web search",
362→		"web search for",
363→		"search the web",
364→		"websearch",
365→		"latest news",
366→		"today news",
367→		"today's news",
368→		"news headlines",
369→		"top stories",
370→		"搜索今天的新闻",
371→		"搜索一下",
372→		"请搜索",
373→		"帮我搜索",
374→		"用 websearch",
375→		"网页搜索",
376→	}
377→	for _, fragment := range intentFragments {
378→		if strings.Contains(lower, fragment) {
379→			return true
380→		}
381→	}
382→
383→	return false
384→}
385→
386→// BuildSyntheticWebSearchToolCallTextFromRequest synthesizes a Claude-compatible
387→// textual web_search tool call from the original Claude request when Codex has
388→// not yet emitted the final action payload.
389→func BuildSyntheticWebSearchToolCallTextFromRequest(rawJSON []byte) string {
390→	query := InferBuiltinWebSearchQuery(rawJSON)
391→	if query == "" {
392→		return ""
393→	}
394→
395→	payload := map[string]any{
396→		"name": "web_search",
397→		"arguments": map[string]any{
398→			"query": query,
399→		},
400→	}
401→	body, err := json.Marshal(payload)
402→	if err != nil {
403→		return ""
404→	}
405→	return "Searching the web.\n\n<tool_call>\n" + string(body) + "\n</tool_call>"
406→}
