408→func normalizeLikelyWebSearchQuery(text string) string {
409→	text = strings.TrimSpace(text)
410→	if text == "" {
411→		return ""
412→	}
413→
414→	if explicit := extractExplicitSearchQuery(text); explicit != "" {
415→		return explicit
416→	}
417→
418→	prefixes := []string{
419→		"perform a web search for the query:",
420→		"perform web search for the query:",
421→		"perform a web search for:",
422→		"web search for the query:",
423→		"web search for:",
424→		"search for:",
425→		"搜索：",
426→		"搜索:",
427→		"请搜索：",
428→		"请搜索:",
429→	}
430→
431→	lower := strings.ToLower(text)
432→	for _, prefix := range prefixes {
433→		if strings.HasPrefix(lower, prefix) {
434→			text = strings.TrimSpace(text[len(prefix):])
435→			break
436→		}
437→	}
438→
439→	return sanitizeLikelySearchQuery(text)
440→}
441→
442→func extractExplicitSearchQuery(text string) string {
443→	lines := strings.Split(strings.ReplaceAll(strings.ReplaceAll(text, "\r\n", "\n"), "\r", "\n"), "\n")
444→	for _, rawLine := range lines {
445→		line := strings.TrimSpace(rawLine)
446→		if line == "" {
447→			continue
448→		}
449→
450→		lower := strings.ToLower(line)
451→		switch {
452→		case strings.HasPrefix(lower, "arguments:"):
453→			return sanitizeLikelySearchQuery(strings.TrimSpace(line[len("arguments:"):]))
454→		case strings.HasPrefix(lower, "query:"):
455→			return sanitizeLikelySearchQuery(strings.TrimSpace(line[len("query:"):]))
456→		}
457→	}
458→
459→	return ""
460→}
461→
462→func sanitizeLikelySearchQuery(text string) string {
463→	text = strings.ReplaceAll(text, "\r\n", "\n")
464→	text = strings.ReplaceAll(text, "\r", "\n")
465→	text = strings.TrimSpace(text)
466→	if text == "" {
467→		return ""
468→	}
469→
470→	lines := strings.Split(text, "\n")
471→	parts := make([]string, 0, 2)
472→	for _, rawLine := range lines {
473→		line := strings.TrimSpace(rawLine)
474→		if line == "" {
475→			if len(parts) > 0 {
476→				break
477→			}
478→			continue
479→		}
480→		if looksLikeSearchQueryNoise(line) {
481→			break
482→		}
483→		parts = append(parts, line)
484→		if len(parts) >= 2 {
485→			break
486→		}
487→	}
488→
489→	if len(parts) == 0 {
490→		return ""
491→	}
492→
493→	query := strings.Join(parts, " ")
494→	query = strings.Join(strings.Fields(query), " ")
495→	query = strings.Trim(query, " \t\r\n\"'“”‘’")
496→	queryLower := strings.ToLower(query)
497→	switch {
498→	case strings.HasPrefix(queryLower, "web search "):
499→		query = strings.TrimSpace(query[len("web search "):])
500→	case strings.HasPrefix(queryLower, "search "):
501→		query = strings.TrimSpace(query[len("search "):])
502→	}
503→	if query == "" {
504→		return ""
505→	}
506→	if len(query) > 220 {
507→		return ""
508→	}
509→	if looksLikeSearchQueryNoise(query) {
510→		return ""
511→	}
512→	return query
513→}
514→
515→func looksLikeSearchQueryNoise(text string) bool {
516→	trimmed := strings.TrimSpace(text)
517→	if trimmed == "" {
518→		return true
519→	}
520→
521→	lower := strings.ToLower(trimmed)
522→	noisePrefixes := []string{
523→		"<system-reminder>",
524→		"arguments:",
525→		"query:",
526→		"import ",
527→		"from ",
528→		"def ",
529→		"class ",
530→		"func ",
531→		"package ",
532→		"python3 ",
533→		"curl ",
534→		"go test ",
535→		"sed -n ",
536→		"rg -n ",
537→		"cases =",
538→		"results =",
539→		"with open(",
540→		"for prompt in",
541→		"p = subprocess",
542→		"event:",
543→		"data:",
544→		"```",
545→		"read the output of the terminal command",
546→		"then fix the error",
547→		"then rerun the command",
548→		"repeat this debugging process",
549→		"use context7",
550→		"use brave-search",
551→		"读终端命令的输出",
552→		"然后修复该错误",
553→		"接着在终端中重新运行该命令",
554→		"如果再次出现错误",
555→		"使用 context7",
556→		"使用 brave-search",
557→	}
558→	for _, prefix := range noisePrefixes {
559→		if strings.HasPrefix(lower, prefix) {
560→			return true
561→		}
562→	}
563→
564→	if strings.Contains(lower, "with open(") ||
565→		strings.Contains(lower, "subprocess.run(") ||
566→		strings.Contains(lower, "json.dump(") ||
567→		strings.Contains(lower, "capture_output=true") ||
568→		strings.Contains(lower, "<tool_call>") {
569→		return true
570→	}
571→
572→	return false
573→}
